import{_ as t,o as a,c as i,ag as r}from"./chunks/framework.Cqf6AMW8.js";const c=JSON.parse('{"title":"HTML 列表、表格与表单","description":"HTML 列表、表格与表单相关标签的使用方法。","frontmatter":{"title":"HTML 列表、表格与表单","description":"HTML 列表、表格与表单相关标签的使用方法。","date":"2026-04-21T00:00:00.000Z","tags":["HTML","列表","表格","表单"],"sidebar":"auto"},"headers":[],"relativePath":"docs/frontend/html/HTML-2-列表-表格-表单.md","filePath":"docs/frontend/html/HTML-2-列表-表格-表单.md","lastUpdated":1776715536000}'),o={name:"docs/frontend/html/HTML-2-列表-表格-表单.md"};function e(n,l,s,u,h,d){return a(),i("div",null,[...l[0]||(l[0]=[r('<p>#HTML</p><h1 id="html进阶标签" tabindex="-1">HTML进阶标签 <a class="header-anchor" href="#html进阶标签" aria-label="Permalink to &quot;HTML进阶标签&quot;">​</a></h1><h2 id="_1-列表相关" tabindex="-1">1. 列表相关 <a class="header-anchor" href="#_1-列表相关" aria-label="Permalink to &quot;1. 列表相关&quot;">​</a></h2><h3 id="无序列表-重点" tabindex="-1">无序列表（重点） <a class="header-anchor" href="#无序列表-重点" aria-label="Permalink to &quot;无序列表（重点）&quot;">​</a></h3><ul><li>ul嵌套li <ul><li><strong>注意事项</strong>： <ul><li>ul里只能写li</li><li>li里可以写p/h等</li></ul></li></ul></li></ul><h3 id="有序列表" tabindex="-1">有序列表 <a class="header-anchor" href="#有序列表" aria-label="Permalink to &quot;有序列表&quot;">​</a></h3><ul><li>ol嵌套li <ul><li><strong>注意事项</strong>：与无序列表相同</li></ul></li></ul><h3 id="定义列表" tabindex="-1">定义列表 <a class="header-anchor" href="#定义列表" aria-label="Permalink to &quot;定义列表&quot;">​</a></h3><ul><li>dl嵌套dd/dt <ul><li><strong>说明</strong>： <ul><li>dt是标题，dd是描述</li><li>一般用于页脚，做一个尾部服务栏目</li></ul></li></ul></li></ul><p>======================================================</p><h2 id="_2-表格相关" tabindex="-1">2. 表格相关 <a class="header-anchor" href="#_2-表格相关" aria-label="Permalink to &quot;2. 表格相关&quot;">​</a></h2><h3 id="表格结构" tabindex="-1">表格结构 <a class="header-anchor" href="#表格结构" aria-label="Permalink to &quot;表格结构&quot;">​</a></h3><ul><li>table嵌套tr，tr嵌套td/th <ul><li><strong>table</strong>：说明这是一个表格</li><li><strong>tr</strong>：一个tr开启一行</li><li><strong>th</strong>：这一行的头单元格</li><li><strong>td</strong>：这一行的内容单元格</li></ul></li></ul><h3 id="表格属性" tabindex="-1">表格属性 <a class="header-anchor" href="#表格属性" aria-label="Permalink to &quot;表格属性&quot;">​</a></h3><ul><li><strong>border属性</strong>：给表格增加边框</li></ul><h3 id="合并单元格" tabindex="-1">合并单元格 <a class="header-anchor" href="#合并单元格" aria-label="Permalink to &quot;合并单元格&quot;">​</a></h3><ul><li><strong>原则</strong>： <ul><li>保留最左最上的单元格，其余要合并的单元格删除</li><li>如果是跨行，保留上，写rowspan（同列和）</li><li>如果是跨列，保留左，写colspan（同行和）</li></ul></li><li><strong>注意</strong>：不能跨单元格合并</li></ul><p>======================================================</p><h2 id="_3-表单相关" tabindex="-1">3. 表单相关 <a class="header-anchor" href="#_3-表单相关" aria-label="Permalink to &quot;3. 表单相关&quot;">​</a></h2><h3 id="表单元素" tabindex="-1">表单元素 <a class="header-anchor" href="#表单元素" aria-label="Permalink to &quot;表单元素&quot;">​</a></h3><ul><li>配合form使用，写在form里</li><li>input标签，根据type属性值不同，作用也不同</li></ul><h3 id="input标签类型" tabindex="-1">input标签类型 <a class="header-anchor" href="#input标签类型" aria-label="Permalink to &quot;input标签类型&quot;">​</a></h3><ul><li><p><strong>text</strong>：文本框</p></li><li><p><strong>password</strong>：密码框</p></li><li><p><strong>radio</strong>：单选框</p></li><li><p><strong>checkbox</strong>：多选框</p></li><li><p><strong>file</strong>：上传文件</p></li></ul><h3 id="input标签属性" tabindex="-1">input标签属性 <a class="header-anchor" href="#input标签属性" aria-label="Permalink to &quot;input标签属性&quot;">​</a></h3><ul><li><p><strong>文本框/密码框的占位文本</strong>：placeholder（提示输入信息）</p></li><li><p><strong>单选框的选择</strong>：name（给该选择绑定元素，无name则无法单选）、checked（默认）</p></li><li><p><strong>多选框的选择</strong>：checked（默认选择）</p></li><li><p><strong>上传文件的属性</strong>：multiple（上传多份文件）</p></li></ul><h3 id="下拉菜单" tabindex="-1">下拉菜单 <a class="header-anchor" href="#下拉菜单" aria-label="Permalink to &quot;下拉菜单&quot;">​</a></h3><ul><li>select嵌套option <ul><li><strong>select</strong>：总属性</li><li><strong>option</strong>：元素</li></ul></li><li><strong>默认选择属性</strong>：selected</li></ul><h3 id="文本域" tabindex="-1">文本域 <a class="header-anchor" href="#文本域" aria-label="Permalink to &quot;文本域&quot;">​</a></h3><ul><li>多行输入（发评论之类的）</li><li><strong>textarea</strong><ul><li><strong>说明</strong>：右下角有拖拽放大功能，工作中一般禁用</li></ul></li></ul><h3 id="label标签" tabindex="-1">label标签 <a class="header-anchor" href="#label标签" aria-label="Permalink to &quot;label标签&quot;">​</a></h3><ul><li><strong>作用</strong>：增大作用范围</li><li><strong>写法</strong>： <ul><li><strong>写法一</strong>：用label单独包裹选项文本内容 <ul><li>label的for标签与input的id一致就行</li></ul></li><li><strong>写法二</strong>：用label包裹input整体 <ul><li>label包住全部</li><li><strong>推荐</strong>：写法二更推荐</li></ul></li></ul></li><li><strong>说明</strong>：label作用范围宽，input都行</li></ul><h3 id="按钮" tabindex="-1">按钮 <a class="header-anchor" href="#按钮" aria-label="Permalink to &quot;按钮&quot;">​</a></h3><ul><li>button内有type属性</li><li><strong>type类型</strong>： <ul><li><strong>submit</strong>：提交（省略属性标签，默认为该功能）</li><li><strong>reset</strong>：重置（一键清空功能）（需要放在form里）</li><li><strong>button</strong>：配合JavaScript一起使用</li></ul></li></ul><p>======================================================</p><h2 id="_4-布局与字符-后续主要使用div" tabindex="-1">4. 布局与字符(后续主要使用div) <a class="header-anchor" href="#_4-布局与字符-后续主要使用div" aria-label="Permalink to &quot;4. 布局与字符(后续主要使用div)&quot;">​</a></h2><h3 id="布局标签" tabindex="-1">布局标签 <a class="header-anchor" href="#布局标签" aria-label="Permalink to &quot;布局标签&quot;">​</a></h3><ul><li><p><strong>div</strong>：换行标签</p></li><li><p><strong>span</strong>：不换行标签</p></li></ul><h3 id="字符实体" tabindex="-1">字符实体 <a class="header-anchor" href="#字符实体" aria-label="Permalink to &quot;字符实体&quot;">​</a></h3><ul><li><strong>作用</strong>：用来显示被语法占用的字符</li><li><strong>常用字符实体</strong>： <ul><li><strong> </strong>：空格</li><li><strong>&lt;</strong>：＜</li><li><strong>&gt;</strong>：＞</li></ul></li></ul>',39)])])}const p=t(o,[["render",e]]);export{c as __pageData,p as default};
